def is_prime(num):
    if num <= 1:
        return False
    for i in range(2, int(num**0.5) + 1):
        if num % i == 0:
            return False
    return True

def count_primes_up_to_n(n):
    count = 0
    for i in range(2, n + 1):
        if is_prime(i):
            count += 1
    return count

def solve(*args):
    if len(args) != 1:
        return None
    n = args[0]
    if not isinstance(n, int) or n < 0:
        return None
    return count_primes_up_to_n(n)
